const PARTY_FULL_NAMES = {
  TVK: 'Tamilaga Vettri Kazhagam',
  DMK: 'Dravida Munnetra Kazhagam',
  ADMK: 'All India Anna Dravida Munnetra Kazhagam',
  AIADMK: 'All India Anna Dravida Munnetra Kazhagam',
  INC: 'Indian National Congress',
  PMK: 'Pattali Makkal Katchi',
  BJP: 'Bharatiya Janata Party',
  NTK: 'Naam Tamilar Katchi',
  AMMK: 'Amma Makkal Munnettra Kazagam',
  CPI: 'Communist Party of India',
  'CPI\(M\)': 'Communist Party of India \(Marxist\)',
  VCK: 'Viduthalai Chiruthaigal Katchi',
  IUML: 'Indian Union Muslim League',
  MDMK: 'Marumalarchi Dravida Munnetra Kazhagam',
  DMDK: 'Desiya Murpokku Dravida Kazhagam',
  IND: 'Independent',
};
const FULL_TO_ABBR = new Map\(Object.entries\(PARTY_FULL_NAMES\).map\(\([a,f]\)=>[f.toLowerCase\(\),a]\)\);
const url = 'https://results.eci.gov.in/ResultAcGenMay2026/chartwiseresult-S22.htm';
fetch\(url\).then\(r=>r.text\(\)\).then\(html=>{
  const xm = html.match\(/var xValues\\s*=\\s*\\[\([^\\]]*\)\\]/\);
  const ym = html.match\(/var yValues\\s*=\\s*\\[\([^\\]]*\)\\]/\);
  if\(xm && ym\) {
    const names = [...xm[1].matchAll\(/'\([^']+\)'/g\)].map\(m=>m[1]\);
    const counts = ym[1].split\(','\).map\(s=>parseInt\(s.trim\(\)\)\).filter\(n=>!isNaN\(n\)\);
    names.forEach\(\(n,i\)=>{ const k=n.toLowerCase\(\).trim\(\); const abbr=FULL_TO_ABBR.get\(k\)||n; console.log\(abbr,counts[i]\); }\);
  } else { console.log\('NO MATCH'\); }
}\);
")

