// Fix summary.json — move leading into won
const summary = JSON.parse\(require\('fs'\).readFileSync\('data/summary.json'\)\);
summary.parties = summary.parties.map\(p => \({
  ...p,
  won: p.won + p.leading,
  leading: 0,
  trailing: 0,
}\)\);
require\('fs'\).writeFileSync\('data/summary.json', JSON.stringify\(summary\)\);

// Fix constituencies.json — set all status to Won
